INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', '在STP协议中，在确定端口角色时,可能会用到BPDU中哪些参数 (40) 。 置BPDU报文的核心内容: 。 Root Identifier: 当前根桥的BID。 。 Root Path Cost: 根路径开销。路径开销 (Path Cost) 是一个端口变量，是STP协议用于选择链 路的参考值。STP协议通过计算路径开销，选择较为“强壮”的链路，阻塞多余的链路，将网络修 剪成无环路的树形网络结构。根路径开销就是某端口到根桥所经过的各个桥上的各端口路径开销 的累加值。 。 Bridge Identifier: 本交换设备的BID。 。 Port Identifier: 发送该BPDU的端口1D。PID由两部分构成的，高4位是端口优先级，低 12 位是 Protocol Identifer Protocol Version Identifier BPDU Type Flags Root Identifier Root Path cost Bridge Identifier Port Identifier. Message Age Max Age Hello Time Forward Delay 公众号/拌音/B 站: summer 课堂，提供网工/网规/信安/高项培训辅导', '["A.BPDU TYPE, ROOTID, ROOT PATH COST, BRIDGE ID", "B. FLAGS, ROOT PATH COST, BRIDGE ID, PORT ID", "C. ROOTID, ROOT PATH COST, BRIDGE ID, BRIDGE PORT ID", "D. ROOTID, ROOT PATH COST, BRIDGE ID, PORT ID"]', '', '', 2, '2022年综合知识', '2022,综合知识', 2022);
INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', '路由器A与路由器B之间建立了BGP连接并互相学习到了路由，路由器B都使用缺省定时器。如果路 由器间链路拥塞，导致路由器A收不到路由器B的Keepalive消息，则 (41) 秒后，路由器A认为邻居失 报文时，我们就认为对方出现了问题，手且可以拆除该TCP连接，并且把从对方收到的路由全部删除。', '["A. 30", "B. 90", "C. 120", "D. 180"]', '', '', 2, '2022年综合知识', '2022,综合知识', 2022);
