INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', '下列关于网络传输中零找贝技术的说法，不正确的是 (15) 。 贝次数，只需要2次上下文切换和数据拷贝次数，就可以完成文件的传输，而且2次的数据拷贝过程， 都不需要通过CPU，2次都是由DMA来搬运。所以，总体来看，零描贝技术可以把文件传输的性能提高至 少一倍以上。零拷贝能给我们带来的好处有: 。 ”减少甚至完全避免不必要的CPU拷贝，从而让CPU解脱出来去执行其他的任务 。 减少内存带宽的占用 。 ”通常零描贝技术还能够减少用户空间和操作系统内核空间之间的上下文切换 内核态 ARS 最新多机构网课联系微信: qingsongguo888 特价促销', '["A. 避免操作系统内核空间和用户空间的数据拷贝", "B. 减少应用程序与网卡之间的数据复制", "C. 避免用户线程和内核线程之间的上下文切换", "D. 通过Direct Memory Access传输数据"]', '', '', 2, '2023年综合知识', '2023,综合知识', 2023);
