INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', '利用长度为r+l比特的生成多项式，生成总长为n比特的循环元余校验码 CCRC) 码字，可检出不超 过 (43) 比特的突发错误。 含的项数大于1，则可以检测单个错; 若G(x)含有因子x+1，则可检测出所有奇数个错。最后得出的最 重要的结论是: 具有r个校验位的多项式能检测出所有长度小于等于r的突发性差错。 (《网络工程师 教程第五版》P55) 。', '["A. r", "B. n", "C. r+]", "D. r+n"]', '', '', 2, '2023年综合知识', '2023,综合知识', 2023);
